package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Field;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class GsonBuilderTest {

  private GsonBuilder gsonBuilder;

  @BeforeEach
  void setUp() {
    gsonBuilder = new GsonBuilder();
  }

  @Test
  void testGenerateNonExecutableJson_setsFlagTrueAndReturnsThis() throws Exception {
    // Initially the private field generateNonExecutableJson should be false (default)
    Field field = GsonBuilder.class.getDeclaredField("generateNonExecutableJson");
    field.setAccessible(true);
    boolean initialValue = field.getBoolean(gsonBuilder);
    assertFalse(initialValue);

    // Call the focal method
    GsonBuilder returned = gsonBuilder.generateNonExecutableJson();

    // The method returns the same instance
    assertSame(gsonBuilder, returned);

    // The private field generateNonExecutableJson should now be true
    boolean updatedValue = field.getBoolean(gsonBuilder);
    assertTrue(updatedValue);
  }
}
